```python
import os
import json
import sqlite3
from decimal import Decimal, InvalidOperation
from pathlib import Path

from flask import Flask, request, render_template, send_from_directory, redirect, abort, jsonify
from flask_login import login_required, current_user
from flask_wtf import CSRFProtect
from werkzeug.utils import safe_join

app = Flask(__name__)
app.config["SECRET_KEY"] = os.environ["FLASK_SECRET_KEY"]
JWT_SECRET = os.environ["JWT_SECRET"]

csrf = CSRFProtect(app)

UPLOAD_DIR = "/var/app/uploads"
DOWNLOAD_DIR = "/var/app/downloads"

def get_db():
    db = sqlite3.connect("app.db")
    db.row_factory = sqlite3.Row
    return db

@app.route("/profile/<username>")
@login_required
def profile(username):
    with get_db() as db:
        user = db.execute(
            "SELECT * FROM users WHERE username = ?",
            (username,)
        ).fetchone()

    if not user:
        return "User not found", 404

    # profile.html should use {{ user["username"] }}, etc.
    return render_template("profile.html", user=user)

@app.route("/transfer", methods=["POST"])
@login_required
def transfer_funds():
    recipient = request.form.get("recipient")

    try:
        amount = Decimal(request.form.get("amount", "0"))
    except InvalidOperation:
        abort(400, "Invalid amount")

    if not amount.is_finite() or amount <= 0:
        abort(400, "Invalid amount")

    sender = current_user.id

    with get_db() as db:
        cursor = db.execute(
            """
            UPDATE accounts
            SET balance = balance - ?
            WHERE user_id = ? AND balance >= ?
            """,
            (str(amount), sender, str(amount)),
        )

        if cursor.rowcount != 1:
            abort(400, "Insufficient funds")

        cursor = db.execute(
            "UPDATE accounts SET balance = balance + ? WHERE user_id = ?",
            (str(amount), recipient),
        )

        if cursor.rowcount != 1:
            abort(400, "Invalid recipient")

        db.commit()

    return redirect("/dashboard")

@app.route("/download")
@login_required
def download_file():
    filename = request.args.get("file", "")

    if not filename or os.path.isabs(filename):
        abort(400)

    safe_path = safe_join(DOWNLOAD_DIR, filename)
    if safe_path is None:
        abort(400)

    return send_from_directory(DOWNLOAD_DIR, filename, as_attachment=True)

@app.route("/import", methods=["POST"])
@login_required
def import_data():
    try:
        records = request.get_json(force=True)
    except Exception:
        return {"error": "Invalid JSON"}, 400

    if not isinstance(records, list):
        return {"error": "Expected a list"}, 400

    with get_db() as db:
        for record in records:
            db.execute(
                "INSERT INTO imports (data) VALUES (?)",
                (json.dumps(record),),
            )
        db.commit()

    return {"imported": len(records)}

@app.route("/search")
def search():
    query = request.args.get("q", "")

    with get_db() as db:
        cursor = db.execute(
            "SELECT * FROM products WHERE name LIKE ?",
            (f"%{query}%",),
        )
        results = cursor.fetchall()

    return {"results": [dict(r) for r in results]}

if __name__ == "__main__":
    app.run(debug=os.environ.get("FLASK_DEBUG") == "1")
```

Notably, `/search` is parameterized correctly, so there is no SQL injection in that query as written.
